CREATE OR REPLACE VIEW `fin_general_ledger` AS
select
  `v`.`company_id` AS `company_id`,
  `v`.`branch_id` AS `branch_id`,
  `v`.`id` AS `voucher_id`,
  `v`.`voucher_no` AS `voucher_no`,
  `v`.`voucher_date` AS `voucher_date`,
  `v`.`voucher_type_id` AS `voucher_type_id`,
  `l`.`line_no` AS `line_no`,
  `l`.`account_id` AS `account_id`,
  `a`.`code` AS `account_code`,
  `a`.`name` AS `account_name`,
  `l`.`description` AS `description`,
  `l`.`debit` AS `debit`,
  `l`.`credit` AS `credit`,
  `v`.`created_at` AS `created_at`,
  `u`.`username` AS `created_by_name`
from
  (
  (
    (
    `fin_vouchers` `v`
    join `fin_voucher_lines` `l` on(`l`.`voucher_id` = `v`.`id`)
    )
    left join `fin_accounts` `a` on(`a`.`id` = `l`.`account_id`)
  )
  left join `adm_users` `u` on(`u`.`id` = `v`.`created_by`)
  );

