  `sb`.`serial_no` AS `serial_no`,
  `sb`.`expiry_date` AS `expiry_date`,
  `sb`.`qty` AS `qty`,
  `sb`.`reserved_qty` AS `reserved_qty`,
  `sb`.`entry_date` AS `entry_date`,
