# ------------------------------------------------------------
# SCHEMA DUMP FOR TABLE: v_inv_issue_register
# ------------------------------------------------------------

CREATE OR REPLACE VIEW `v_inv_issue_register` AS
select
  `i`.`company_id` AS `company_id`,
  `i`.`branch_id` AS `branch_id`,
  `i`.`id` AS `issue_id`,
  `i`.`issue_no` AS `issue_no`,
  `i`.`issue_date` AS `issue_date`,
  `i`.`issue_type` AS `issue_type`,
  `i`.`warehouse_id` AS `warehouse_id`,
  `i`.`department_id` AS `department_id`,
  `d`.`item_id` AS `item_id`,
  `d`.`qty_issued` AS `qty_issued`,
  `d`.`uom` AS `uom`,
  coalesce(
  (
    select
    sum(`rd`.`qty_returned`)
    from
    (
      `inv_return_to_stores` `r`
      join `inv_return_to_stores_details` `rd` on(`rd`.`rts_id` = `r`.`id`)
    )
    where
    `r`.`company_id` = `i`.`company_id`
    and `r`.`branch_id` = `i`.`branch_id`
    and `rd`.`item_id` = `d`.`item_id`
    and `r`.`department_id` <= > `i`.`department_id`
    and `r`.`warehouse_id` <= > `i`.`warehouse_id`
    and `r`.`rts_date` >= `i`.`issue_date`
  ),
  0
  ) AS `returned_qty`,
  coalesce(`d`.`qty_issued`, 0) - coalesce(
  (
    select
    sum(`rd`.`qty_returned`)
    from
    (
      `inv_return_to_stores` `r`
      join `inv_return_to_stores_details` `rd` on(`rd`.`rts_id` = `r`.`id`)
    )
    where
    `r`.`company_id` = `i`.`company_id`
    and `r`.`branch_id` = `i`.`branch_id`
    and `rd`.`item_id` = `d`.`item_id`
    and `r`.`department_id` <= > `i`.`department_id`
    and `r`.`warehouse_id` <= > `i`.`warehouse_id`
    and `r`.`rts_date` >= `i`.`issue_date`
  ),
  0
  ) AS `remaining_qty`,
  `i`.`created_by` AS `created_by`,
  `i`.`created_at` AS `created_at`,
  `u`.`username` AS `created_by_name`
from
  (
  (
    `inv_issue_to_requirement` `i`
    join `inv_issue_to_requirement_details` `d` on(`d`.`issue_id` = `i`.`id`)
  )
  left join `adm_users` `u` on(`u`.`id` = `i`.`created_by`)
  );

