  coalesce(`sb`.`qty`, 0) AS `opening_qty`,
  coalesce(`sb`.`qty`, 0) AS `closing_qty`,
  `sb`.`created_at` AS `created_at`,
  `u`.`username` AS `created_by_name`
from
